// Token-Zaehler. Heuristik chars/4 + Wortanzahl. model: gpt-4o|gpt-4o-mini|claude-sonnet-4-6.
async function run(input) {
  var text = String((input && input.text) || '');
  var model = String((input && input.model) || '').toLowerCase();
  var zeichen = text.length;
  var woerter = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;
  var byChars = zeichen / 4;
  var byWords = woerter * 1.33;
  var tokens = Math.round((byChars + byWords) / 2);
  if (tokens < woerter) tokens = woerter;
  var prices = { 'gpt-4o': 2.5, 'gpt-4o-mini': 0.15, 'claude-sonnet-4-6': 3.0 };
  var out = {
    zeichen: zeichen,
    woerter: woerter,
    tokensGeschaetzt: tokens,
    hinweis: 'Grobe Schaetzung (kein echter Tokenizer).'
  };
  if (prices[model] != null) {
    out.modell = model;
    out.preisProMillionUSD = prices[model];
    out.kostenInputUSD = Math.round(tokens / 1e6 * prices[model] * 1e6) / 1e6;
  }
  return out;
}
